import{_ as e,c as o,o as l,ac as s}from"./chunks/framework.CtEZafqV.js";const h=JSON.parse('{"title":"Note 7","description":"","frontmatter":{},"headers":[],"relativePath":"engineering/notes/No.7.md","filePath":"engineering/notes/No.7.md","lastUpdated":1763634884000}'),n={name:"engineering/notes/No.7.md"};function d(r,t,i,a,c,g){return l(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="note-7" tabindex="-1">Note 7 <a class="header-anchor" href="#note-7" aria-label="Permalink to &quot;Note 7&quot;">​</a></h1><h2 id="前端打包对于图片资源是否需要进行-gzip-br-压缩" tabindex="-1">前端打包对于图片资源是否需要进行 gzip/br 压缩 <a class="header-anchor" href="#前端打包对于图片资源是否需要进行-gzip-br-压缩" aria-label="Permalink to &quot;前端打包对于图片资源是否需要进行 gzip/br 压缩&quot;">​</a></h2><p><strong>通常情况下，不需要也不应该对已经压缩过的图片格式（如 <code>JPEG</code>, <code>PNG</code>, <code>WebP</code>, <code>AVIF</code>）进行 <code>Gzip</code> 或 <code>Brotli</code> 压缩。</strong></p><h3 id="为什么不需要-主要原因有三点" tabindex="-1">为什么不需要？主要原因有三点： <a class="header-anchor" href="#为什么不需要-主要原因有三点" aria-label="Permalink to &quot;为什么不需要？主要原因有三点：&quot;">​</a></h3><ol><li><p><strong>收益极低，甚至可能适得其反</strong></p><ul><li><strong>工作原理</strong>：<code>Gzip</code> 和 <code>Brotli</code> 这类压缩算法主要针对<strong>文本内容</strong>进行优化。它们通过查找和替换重复的字符串模式来减小文件大小。</li><li><strong>图片的本质</strong>：像 <code>JPEG</code>、<code>PNG</code> 这类常见的图片格式，其本身就是<strong>已经压缩过的二进制格式</strong>。它们使用了各自的压缩算法（如 <code>JPEG</code> 的有损压缩，<code>PNG</code> 的无损压缩）来尽可能减少文件大小。图片文件中的数据（尤其是照片类 <code>JPEG</code>）已经非常随机，几乎没有可供 <code>Gzip</code>/<code>Brotli</code> 再次压缩的重复模式。</li><li><strong>结果</strong>：试图对它们进行二次压缩，压缩率会非常低（通常只有 <code>2%-5%</code> 的缩小），有时甚至因为压缩文件头等元数据的增加，导致压缩后的文件比原文件<strong>更大</strong>。这个过程浪费了服务器 <code>CPU</code> 资源，却几乎没有换来任何带宽节省。</li></ul></li><li><p><strong>浪费服务器和客户端资源</strong></p><ul><li><strong>服务器 CPU</strong>：服务器需要对每个请求的图片资源进行实时压缩（如果配置了动态压缩），或者需要预先存储压缩后的版本。这对于大量图片的网站来说，是一笔不小的 <code>CPU</code> 开销。</li><li><strong>客户端 CPU</strong>：浏览器在下载完成后，需要解压这些资源才能渲染。虽然现代设备解压很快，但这个不必要的步骤仍然会消耗设备电量，并在极端情况下可能略微延迟图片的渲染时间。</li></ul></li><li><p><strong>现代图片格式已经足够优秀</strong></p><ul><li>现在主流的现代图片格式，如 <strong>WebP</strong> 和 <strong>AVIF</strong>，相比传统的 <code>JPEG</code> 和 <code>PNG</code>，在同等质量下拥有更小的文件体积。将精力放在<strong>将图片转换为现代格式</strong>上，其收益远远大于对旧格式进行 <code>Gzip/Brotli</code> 压缩。</li></ul></li></ol><h3 id="什么时候需要对-图片-进行-gzip-brotli-压缩" tabindex="-1">什么时候需要对“图片”进行 <code>Gzip/Brotli</code> 压缩？ <a class="header-anchor" href="#什么时候需要对-图片-进行-gzip-brotli-压缩" aria-label="Permalink to &quot;什么时候需要对“图片”进行 \`Gzip/Brotli\` 压缩？&quot;">​</a></h3><br><p>有一个重要的例外情况：<strong>对 <code>SVG</code> 格式的图片进行压缩。</strong></p><p><strong>为什么 <code>SVG</code> 需要压缩？</strong></p><ul><li><strong>SVG 的本质</strong>：<code>SVG（Scalable Vector Graphics）</code>文件本身是 <strong>XML 格式的文本文件</strong>。它里面包含的是标签、路径数据、样式等文本信息，这些信息有很多重复的模式（例如大量的 <code>&lt;path&gt;</code> 标签、重复的样式定义等）。</li><li><strong>高压缩率</strong>：正因为它是文本，所以 <code>Gzip</code> 或 <code>Brotli</code> 对其压缩效果非常显著，通常可以减少 <strong>50% - 80%</strong> 的体积。这对于复杂的 <code>SVG</code> 图标或插图来说是巨大的性能提升。</li></ul><p><strong>最佳实践建议：</strong></p><ul><li><p>在 <code>Nginx</code> 或 <code>Apache</code> 等服务器的配置中，确保将 <code>SVG</code> 文件包含在需要压缩的 <code>MIME</code> 类型中。</p></li><li><p>例如在 <code>Nginx</code> 中：</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">gzip_types</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  text/plain</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  text/css</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  text/xml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  text/javascript</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  application/javascript</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  application/xml+rss</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  application/json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  image/svg+xml; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 确保包含这一行！</span></span></code></pre></div></li></ul><h3 id="总结与最佳实践" tabindex="-1">总结与最佳实践 <a class="header-anchor" href="#总结与最佳实践" aria-label="Permalink to &quot;总结与最佳实践&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">资源类型</th><th style="text-align:left;">推荐使用 <code>Gzip/Brotli</code></th><th style="text-align:left;">原因</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>HTML, CSS, JS, JSON</strong></td><td style="text-align:left;"><strong>强烈推荐</strong></td><td style="text-align:left;">文本文件，包含大量重复模式，压缩效果极佳。</td></tr><tr><td style="text-align:left;"><strong>SVG 图片</strong></td><td style="text-align:left;"><strong>强烈推荐</strong></td><td style="text-align:left;">本质是 <code>XML</code> 文本，压缩率非常高。</td></tr><tr><td style="text-align:left;"><strong>JPEG, PNG, GIF</strong></td><td style="text-align:left;"><strong>不推荐</strong></td><td style="text-align:left;">已是压缩过的二进制格式，二次压缩收益极低，浪费资源。</td></tr><tr><td style="text-align:left;"><strong>WebP, AVIF</strong></td><td style="text-align:left;"><strong>不推荐</strong></td><td style="text-align:left;">采用更先进的压缩算法，已是压缩后的最佳状态。</td></tr></tbody></table><p><strong>所以，对于前端项目打包后的图片资源，你应该做的是：</strong></p><ol><li><strong>格式优化</strong>：将项目中的 <code>JPEG</code>、<code>PNG</code> 图片转换为 <strong>WebP</strong> 格式。现在浏览器支持度已经非常广，能带来显著的体积减小。</li><li><strong>质量调整</strong>：根据使用场景（如大图展示 vs. 小图标），适当降低图片的输出质量。</li><li><strong>尺寸适配</strong>：根据不同的设备和屏幕尺寸，输出不同尺寸的图片（响应式图片，使用 <code>srcset</code> 和 <code>sizes</code> 属性）。</li><li><strong>压缩 SVG</strong>：确保你的构建流程或服务器对 <code>SVG</code> 文件启用了 <code>Brotli</code>（优先）或 <code>Gzip</code> 压缩。</li><li><strong>CDN 与缓存</strong>：使用 <code>CDN</code> 并配置正确的缓存策略，这比压缩图片本身带来的性能提升可能更大。</li></ol><p>通过以上这些方法，你可以更高效地优化前端项目中的图片资源，而不是在效果甚微的 <code>Gzip/Brotli</code> 压缩上浪费时间。</p><h2 id="静态资源是否需要全部放到-cdn-上" tabindex="-1">静态资源是否需要全部放到 CDN 上？ <a class="header-anchor" href="#静态资源是否需要全部放到-cdn-上" aria-label="Permalink to &quot;静态资源是否需要全部放到 CDN 上？&quot;">​</a></h2><p><strong>静态资源不需要，也不应该“全部”放到<code>CDN</code>上。</strong> 这是一个需要根据资源类型、业务需求、成本和架构进行权衡的决策。</p><h3 id="为什么需要把大部分静态资源放到cdn上-放cdn的好处" tabindex="-1">为什么需要把大部分静态资源放到CDN上？（放CDN的好处） <a class="header-anchor" href="#为什么需要把大部分静态资源放到cdn上-放cdn的好处" aria-label="Permalink to &quot;为什么需要把大部分静态资源放到CDN上？（放CDN的好处）&quot;">​</a></h3><br><p>将<strong>主要的、公共的</strong>静态资源（如<code>JS</code>、<code>CSS</code>、图片、字体、视频）放到<code>CDN</code>上，主要是为了：</p><ol><li><p><strong>极致性能，降低延迟</strong></p><ul><li><strong>就近访问</strong>：<code>CDN</code>在全球分布有多个边缘节点，用户可以从地理上最近的节点获取资源，极大减少网络传输的延迟。</li><li><strong>缓存命中</strong>：热门资源会被缓存在各个边缘节点，用户请求无需回源，直接命中缓存，速度极快。</li></ul></li><li><p><strong>减轻源站服务器负载</strong></p><ul><li>静态资源请求占据了网站流量的绝大部分。将这些请求分流到<code>CDN</code>，可以显著减少源站服务器的带宽、<code>CPU</code>和连接数压力，让源站更专注于处理动态API请求。</li></ul></li><li><p><strong>提升可用性和容灾能力</strong></p><ul><li>即使源站服务器因故障暂时宕机，用户仍然可以从<code>CDN</code>缓存中获取已缓存的静态资源，网站至少可以部分访问（虽然动态功能会失效）。</li><li><code>CDN</code>本身具备高可用和负载均衡能力，能抵御一定程度的流量冲击（如热点事件、<code>DDoS</code>攻击的一部分）。</li></ul></li><li><p><strong>优化带宽成本</strong></p><ul><li><code>CDN</code>厂商的带宽单价通常比你自己购买云服务器带宽要便宜。对于流量巨大的网站，使用<code>CDN</code>能节省可观的带宽费用。</li></ul></li></ol><h3 id="不放cdn时有什么问题" tabindex="-1">不放CDN时有什么问题？ <a class="header-anchor" href="#不放cdn时有什么问题" aria-label="Permalink to &quot;不放CDN时有什么问题？&quot;">​</a></h3><br><p>如果不使用<code>CDN</code>，所有静态资源都直接从你的<strong>源站服务器</strong>提供，会面临：</p><ol><li><strong>用户体验差</strong>：对于远离你机房的用户，加载速度会明显变慢，首屏时间变长。</li><li><strong>服务器压力大</strong>：所有静态资源请求都直接打到源站，容易在流量高峰时成为性能瓶颈，导致服务器响应变慢甚至崩溃。</li><li><strong>单点故障风险</strong>：源站成为唯一的出入口，一旦出现问题，整个网站完全无法访问。</li><li><strong>成本可能更高</strong>：为了应对峰值流量，你可能需要购买更高配置的服务器和更昂贵的带宽，但大部分时间这些资源是闲置的。</li></ol><h3 id="全放cdn上又有什么问题-不放cdn的-反向-问题" tabindex="-1">全放CDN上又有什么问题？（不放CDN的“反向”问题） <a class="header-anchor" href="#全放cdn上又有什么问题-不放cdn的-反向-问题" aria-label="Permalink to &quot;全放CDN上又有什么问题？（不放CDN的“反向”问题）&quot;">​</a></h3><br><p>把<strong>所有</strong>静态资源，不加区分地都放到<code>CDN</code>上，也会引入新的问题：</p><ol><li><p><strong>架构复杂性和运维成本</strong></p><ul><li><strong>缓存策略复杂</strong>：你需要为不同类型的资源（如长期不变的<code>JS</code>/<code>CSS</code>、频繁更新的商品图、敏感文件）配置不同的缓存过期时间、缓存键规则。</li><li><strong>刷新失效挑战</strong>：当资源更新时，你需要手动或通过<code>API</code>去刷新<code>CDN</code>缓存，以确保用户能获取到最新版本。如果刷新不及时或配置错误，会导致用户看到旧版本，即“缓存污染”问题。</li></ul></li><li><p><strong>安全性风险</strong></p><ul><li><strong>攻击面扩大</strong>：<code>CDN</code>的<code>URL</code>是公开的，如果你的资源链接被爬取或泄露，<code>CDN</code>会成为<code>DDoS</code>攻击的入口，虽然它能缓解一部分，但攻击流量依然会产生费用。</li><li><strong>敏感信息泄露</strong>：如果将本应<strong>私有的、带权限验证的</strong>静态资源（如用户上传的合同、隐私图片）错误地放到了公共<code>CDN</code>上，可能会导致严重的数据泄露。<strong>这类资源绝对不能放公共CDN。</strong></li></ul></li><li><p><strong>成本问题</strong></p><ul><li><strong>CDN流量费用</strong>：虽然单价低，但总量巨大时，<code>CDN</code>费用也会非常可观。</li><li><strong>回源流量费用</strong>：当<code>CDN</code>节点缓存未命中时，需要回源站拉取资源，这部分流量（回源流量）也是需要付费的。如果资源更新过于频繁或缓存配置不当，会导致大量回源，成本不降反升。</li></ul></li><li><p><strong>潜在的稳定性问题</strong></p><ul><li><strong>CDN服务商故障</strong>：虽然概率极低，但一旦你的<code>CDN</code>服务商出现全局性故障，你的网站静态资源将全部无法加载。你需要有降级方案（例如，在检测到<code>CDN</code>失败时，动态地将资源<code>URL</code>切换回源站）。</li></ul></li></ol><h3 id="最佳实践与总结" tabindex="-1">最佳实践与总结 <a class="header-anchor" href="#最佳实践与总结" aria-label="Permalink to &quot;最佳实践与总结&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">资源类型</th><th style="text-align:left;">推荐做法</th><th style="text-align:left;">原因</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>公共前端资源</strong><br>(<code>JS</code>, <code>CSS</code>, 字体, 公共图片)</td><td style="text-align:left;"><strong>强烈推荐放CDN</strong></td><td style="text-align:left;">用户受益最大，缓存效果好，能显著提升网站性能。</td></tr><tr><td style="text-align:left;"><strong>用户生成内容</strong><br>(<code>UGC</code>， 如用户头像、商品图)</td><td style="text-align:left;"><strong>推荐放CDN</strong></td><td style="text-align:left;">量大，访问分散，非常适合<code>CDN</code>分发。但需注意图片处理（缩略图等）。</td></tr><tr><td style="text-align:left;"><strong>大文件</strong><br>(<code>App</code>安装包、视频)</td><td style="text-align:left;"><strong>必须放CDN</strong></td><td style="text-align:left;">节省源站带宽，加速下载，是<code>CDN</code>的核心应用场景。</td></tr><tr><td style="text-align:left;"><strong>私密/敏感文件</strong><br>(付费内容、用户合同)</td><td style="text-align:left;"><strong>不放公共CDN，或使用</strong><br><strong>带鉴权的私有CDN</strong></td><td style="text-align:left;">安全第一。公共<code>CDN</code>无法保证隐私，必须通过源站或专门的私有资源服务进行权限校验。</td></tr><tr><td style="text-align:left;"><strong>频繁实时更新的小文件</strong><br>(如<code>JSON</code>配置， 实时行情图)</td><td style="text-align:left;"><strong>谨慎使用CDN，或设置很短缓存</strong></td><td style="text-align:left;">缓存反而会导致数据延迟。如果对实时性要求极高，可能直接回源更快。</td></tr><tr><td style="text-align:left;"><strong>开发/测试环境资源</strong></td><td style="text-align:left;"><strong>通常不放CDN</strong></td><td style="text-align:left;">避免不必要的成本，且需要频繁更新，缓存会带来调试困扰。</td></tr></tbody></table><h3 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h3><br><p><strong>采用“动静分离”的架构是基本原则。</strong> 将公共的、不变的、量大的静态资源交给<code>CDN</code>，以提升性能和降低成本；而将动态的、私密的、实时性要求极高的资源保留在源站或通过专门的、安全的服务来处理。</p><p>不要走极端，<strong>“全放”和“全不放”都是不合理的</strong>。正确的做法是根据业务场景和资源特性，制定精细化的<code>CDN</code>使用策略。</p>`,37)])])}const N=e(n,[["render",d]]);export{h as __pageData,N as default};
